import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read entire line

        int maxLength = Math.min(name.length(), 10); // Limit input length to buffer size

        char[] buffer = new char[maxLength]; // Buffer with limited size

        for (int i = 0; i < maxLength; i++) {
            buffer[i] = name.charAt(i); // Copying user input into buffer
        }

        System.out.println("Hello, " + new String(buffer)); // Outputting the buffer

        scanner.close();
    }
}

